FILES[r"backend\\app\\core\\config.py"] = 'from pydantic_settings import BaseSettings\nfrom typing import List\nimport secrets\n\n\nclass Settings(BaseSettings):\n    # App\n    APP_NAME: str = "PayApp"\n    DEBUG: bool = False\n    SECRET_KEY: str = secrets.token_urlsafe(64)\n\n    # Database\n    DB_HOST: str = "localhost"\n    DB_PORT: int = 5432\n    DB_NAME: str = "payapp"\n    DB_USER: str = "payadmin"\n    DB_PASSWORD: str = "Adminpa01"\n\n    @property\n    def DATABASE_URL(self) -> str:\n        return f"postgresql+asyncpg://{self.DB_USER}:{self.DB_PASSWORD}@{self.DB_HOST}:{self.DB_PORT}/{self.DB_NAME}"\n\n    @property\n    def DATABASE_URL_SYNC(self) -> str:\n        return f"postgresql://{self.DB_USER}:{self.DB_PASSWORD}@{self.DB_HOST}:{self.DB_PORT}/{self.DB_NAME}"\n\n    # JWT\n    JWT_SECRET_KEY: str = secrets.token_urlsafe(64)\n    JWT_ALGORITHM: str = "HS256"\n    ACCESS_TOKEN_EXPIRE_MINUTES: int = 30\n    REFRESH_TOKEN_EXPIRE_DAYS: int = 7\n\n    # Security\n    BCRYPT_ROUNDS: int = 12\n    MAX_LOGIN_ATTEMPTS: int = 5\n    LOCKOUT_DURATION_MINUTES: int = 15\n\n    # CORS\n    ALLOWED_ORIGINS: List[str] = [\n        "http://localhost:5173",\n        "http://localhost:3000",\n    ]\n    ALLOWED_HOSTS: List[str] = ["localhost", "127.0.0.1"]\n\n    # Rate limiting\n    RATE_LIMIT_PER_MINUTE: int = 60\n    AUTH_RATE_LIMIT_PER_MINUTE: int = 10\n\n    class Config:\n        env_file = ".env"\n        case_sensitive = True\n\n\nsettings = Settings()\n'

FILES[r"backend\\app\\core\\database.py"] = 'from sqlalchemy.ext.asyncio import create_async_engine, AsyncSession, async_sessionmaker\nfrom sqlalchemy.orm import DeclarativeBase\nfrom app.core.config import settings\n\nengine = create_async_engine(\n    settings.DATABASE_URL,\n    echo=settings.DEBUG,\n    pool_pre_ping=True,\n    pool_size=10,\n    max_overflow=20,\n)\n\nAsyncSessionLocal = async_sessionmaker(\n    engine,\n    class_=AsyncSession,\n    expire_on_commit=False,\n)\n\n\nclass Base(DeclarativeBase):\n    pass\n\n\nasync def get_db():\n    async with AsyncSessionLocal() as session:\n        try:\n            yield session\n            await session.commit()\n        except Exception:\n            await session.rollback()\n            raise\n        finally:\n            await session.close()\n\n\nasync def create_tables():\n    async with engine.begin() as conn:\n        await conn.run_sync(Base.metadata.create_all)\n'

FILES[r"backend\\app\\core\\security.py"] = 'from datetime import datetime, timedelta, timezone\nfrom typing import Optional, Union\nimport jwt\nfrom passlib.context import CryptContext\nfrom fastapi import Depends, HTTPException, status\nfrom fastapi.security import HTTPBearer, HTTPAuthorizationCredentials\nfrom sqlalchemy.ext.asyncio import AsyncSession\n\nfrom app.core.config import settings\nfrom app.core.database import get_db\n\npwd_context = CryptContext(\n    schemes=["bcrypt"],\n    deprecated="auto",\n    bcrypt__rounds=settings.BCRYPT_ROUNDS,\n)\n\nsecurity = HTTPBearer()\n\n\ndef hash_password(password: str) -> str:\n    return pwd_context.hash(password)\n\n\ndef verify_password(plain_password: str, hashed_password: str) -> bool:\n    return pwd_context.verify(plain_password, hashed_password)\n\n\ndef create_access_token(data: dict, expires_delta: Optional[timedelta] = None) -> str:\n    to_encode = data.copy()\n    expire = datetime.now(timezone.utc) + (\n        expires_delta or timedelta(minutes=settings.ACCESS_TOKEN_EXPIRE_MINUTES)\n    )\n    to_encode.update({\n        "exp": expire,\n        "iat": datetime.now(timezone.utc),\n        "type": "access",\n    })\n    return jwt.encode(to_encode, settings.JWT_SECRET_KEY, algorithm=settings.JWT_ALGORITHM)\n\n\ndef create_refresh_token(data: dict) -> str:\n    to_encode = data.copy()\n    expire = datetime.now(timezone.utc) + timedelta(days=settings.REFRESH_TOKEN_EXPIRE_DAYS)\n    to_encode.update({\n        "exp": expire,\n        "iat": datetime.now(timezone.utc),\n        "type": "refresh",\n    })\n    return jwt.encode(to_encode, settings.JWT_SECRET_KEY, algorithm=settings.JWT_ALGORITHM)\n\n\ndef decode_token(token: str) -> dict:\n    try:\n        payload = jwt.decode(\n            token,\n            settings.JWT_SECRET_KEY,\n            algorithms=[settings.JWT_ALGORITHM],\n        )\n        return payload\n    except jwt.ExpiredSignatureError:\n        raise HTTPException(\n            status_code=status.HTTP_401_UNAUTHORIZED,\n            detail="Token expirado",\n            headers={"WWW-Authenticate": "Bearer"},\n        )\n    except jwt.InvalidTokenError:\n        raise HTTPException(\n            status_code=status.HTTP_401_UNAUTHORIZED,\n            detail="Token inválido",\n            headers={"WWW-Authenticate": "Bearer"},\n        )\n\n\nasync def get_current_user(\n    credentials: HTTPAuthorizationCredentials = Depends(security),\n    db: AsyncSession = Depends(get_db),\n):\n    from app.models.user import User\n    from sqlalchemy import select\n\n    payload = decode_token(credentials.credentials)\n\n    if payload.get("type") != "access":\n        raise HTTPException(status_code=401, detail="Token inválido")\n\n    user_id: int = payload.get("sub")\n    if not user_id:\n        raise HTTPException(status_code=401, detail="Token inválido")\n\n    result = await db.execute(select(User).where(User.id == int(user_id)))\n    user = result.scalar_one_or_none()\n\n    if not user or not user.is_active:\n        raise HTTPException(status_code=401, detail="Usuario no encontrado o inactivo")\n\n    return user\n\n\ndef require_role(*roles: str):\n    async def role_checker(current_user=Depends(get_current_user)):\n        if current_user.role not in roles:\n            raise HTTPException(\n                status_code=status.HTTP_403_FORBIDDEN,\n                detail="No tiene permisos para esta acción",\n            )\n        return current_user\n    return role_checker\n'

FILES[r"backend\\app\\main.py"] = 'from fastapi import FastAPI\nfrom fastapi.middleware.cors import CORSMiddleware\nfrom fastapi.middleware.trustedhost import TrustedHostMiddleware\nfrom slowapi import Limiter, _rate_limit_exceeded_handler\nfrom slowapi.util import get_remote_address\nfrom slowapi.errors import RateLimitExceeded\n\nfrom app.routers import auth, users, employees, payroll\nfrom app.core.config import settings\nfrom app.middleware.security import SecurityHeadersMiddleware\n\nlimiter = Limiter(key_func=get_remote_address)\n\napp = FastAPI(\n    title="PayApp - Nómina Empresarial",\n    description="Sistema de nómina para PYMES",\n    version="1.0.0",\n    docs_url="/api/docs" if settings.DEBUG else None,\n    redoc_url="/api/redoc" if settings.DEBUG else None,\n)\n\n# Rate limiting\napp.state.limiter = limiter\napp.add_exception_handler(RateLimitExceeded, _rate_limit_exceeded_handler)\n\n# CORS\napp.add_middleware(\n    CORSMiddleware,\n    allow_origins=settings.ALLOWED_ORIGINS,\n    allow_credentials=True,\n    allow_methods=["GET", "POST", "PUT", "DELETE", "PATCH"],\n    allow_headers=["*"],\n)\n\n# Security headers\napp.add_middleware(SecurityHeadersMiddleware)\n\n# Trusted hosts\napp.add_middleware(\n    TrustedHostMiddleware,\n    allowed_hosts=settings.ALLOWED_HOSTS,\n)\n\n# Routers\napp.include_router(auth.router, prefix="/api/v1/auth", tags=["Autenticación"])\napp.include_router(users.router, prefix="/api/v1/users", tags=["Usuarios"])\napp.include_router(employees.router, prefix="/api/v1/employees", tags=["Empleados"])\napp.include_router(payroll.router, prefix="/api/v1/payroll", tags=["Nómina"])\n\n\n@app.get("/api/health")\nasync def health_check():\n    return {"status": "ok", "app": "PayApp"}\n'

