FILES[r"backend\\app\\models\\employee.py"] = 'from sqlalchemy import Column, Integer, String, Numeric, Boolean, DateTime, Date, ForeignKey, Enum as SAEnum\nfrom sqlalchemy.sql import func\nfrom sqlalchemy.orm import relationship\nimport enum\nfrom app.core.database import Base\n\n\nclass EmployeeStatus(str, enum.Enum):\n    activo = "activo"\n    inactivo = "inactivo"\n    suspendido = "suspendido"\n\n\nclass ContractType(str, enum.Enum):\n    indefinido = "indefinido"\n    temporal = "temporal"\n    obra_labor = "obra_labor"\n\n\nclass Employee(Base):\n    __tablename__ = "employees"\n\n    id = Column(Integer, primary_key=True, index=True)\n    employee_code = Column(String(20), unique=True, index=True, nullable=False)\n    first_name = Column(String(100), nullable=False)\n    last_name = Column(String(100), nullable=False)\n    document_id = Column(String(20), unique=True, nullable=False)\n    email = Column(String(255), unique=True, nullable=True)\n    phone = Column(String(20), nullable=True)\n    position = Column(String(150), nullable=False)\n    department = Column(String(100), nullable=False)\n    base_salary = Column(Numeric(12, 2), nullable=False)\n    hire_date = Column(Date, nullable=False)\n    contract_type = Column(SAEnum(ContractType), default=ContractType.indefinido)\n    status = Column(SAEnum(EmployeeStatus), default=EmployeeStatus.activo)\n    is_active = Column(Boolean, default=True)\n    created_at = Column(DateTime(timezone=True), server_default=func.now())\n    updated_at = Column(DateTime(timezone=True), onupdate=func.now())\n\n    payrolls = relationship("Payroll", back_populates="employee")\n\n    @property\n    def full_name(self):\n        return f"{self.first_name} {self.last_name}"\n'

FILES[r"backend\\app\\models\\payroll.py"] = 'from sqlalchemy import Column, Integer, String, Numeric, DateTime, Date, ForeignKey, Enum as SAEnum, Text\nfrom sqlalchemy.sql import func\nfrom sqlalchemy.orm import relationship\nimport enum\nfrom app.core.database import Base\n\n\nclass PayrollStatus(str, enum.Enum):\n    borrador = "borrador"\n    procesado = "procesado"\n    pagado = "pagado"\n    anulado = "anulado"\n\n\nclass Payroll(Base):\n    __tablename__ = "payrolls"\n\n    id = Column(Integer, primary_key=True, index=True)\n    employee_id = Column(Integer, ForeignKey("employees.id"), nullable=False)\n    period_start = Column(Date, nullable=False)\n    period_end = Column(Date, nullable=False)\n    base_salary = Column(Numeric(12, 2), nullable=False)\n    overtime_hours = Column(Numeric(6, 2), default=0)\n    overtime_amount = Column(Numeric(12, 2), default=0)\n    bonuses = Column(Numeric(12, 2), default=0)\n    gross_salary = Column(Numeric(12, 2), nullable=False)\n\n    # Deducciones\n    social_security = Column(Numeric(12, 2), default=0)\n    income_tax = Column(Numeric(12, 2), default=0)\n    other_deductions = Column(Numeric(12, 2), default=0)\n    total_deductions = Column(Numeric(12, 2), nullable=False)\n\n    net_salary = Column(Numeric(12, 2), nullable=False)\n    status = Column(SAEnum(PayrollStatus), default=PayrollStatus.borrador)\n    payment_date = Column(Date, nullable=True)\n    notes = Column(Text, nullable=True)\n    created_by = Column(Integer, ForeignKey("users.id"), nullable=True)\n    created_at = Column(DateTime(timezone=True), server_default=func.now())\n    updated_at = Column(DateTime(timezone=True), onupdate=func.now())\n\n    employee = relationship("Employee", back_populates="payrolls")\n'

FILES[r"backend\\app\\models\\user.py"] = 'from sqlalchemy import Column, Integer, String, Boolean, DateTime, Enum as SAEnum\nfrom sqlalchemy.sql import func\nimport enum\nfrom app.core.database import Base\n\n\nclass UserRole(str, enum.Enum):\n    admin = "admin"\n    operador_nomina = "operador_nomina"\n\n\nclass User(Base):\n    __tablename__ = "users"\n\n    id = Column(Integer, primary_key=True, index=True)\n    email = Column(String(255), unique=True, index=True, nullable=False)\n    username = Column(String(100), unique=True, index=True, nullable=False)\n    full_name = Column(String(255), nullable=False)\n    hashed_password = Column(String(255), nullable=False)\n    role = Column(SAEnum(UserRole), default=UserRole.operador_nomina, nullable=False)\n    is_active = Column(Boolean, default=True)\n    failed_login_attempts = Column(Integer, default=0)\n    locked_until = Column(DateTime(timezone=True), nullable=True)\n    last_login = Column(DateTime(timezone=True), nullable=True)\n    created_at = Column(DateTime(timezone=True), server_default=func.now())\n    updated_at = Column(DateTime(timezone=True), onupdate=func.now())\n'

