FILES[r"backend\\app\\routers\\auth.py"] = 'from fastapi import APIRouter, Depends, HTTPException, status, Request\nfrom sqlalchemy.ext.asyncio import AsyncSession\nfrom sqlalchemy import select\nfrom datetime import datetime, timezone, timedelta\nfrom slowapi import Limiter\nfrom slowapi.util import get_remote_address\n\nfrom app.core.database import get_db\nfrom app.core.security import (\n    verify_password, hash_password, create_access_token,\n    create_refresh_token, decode_token, get_current_user,\n)\nfrom app.core.config import settings\nfrom app.models.user import User\nfrom app.schemas.user import LoginRequest, TokenResponse, UserCreate, UserResponse, RefreshTokenRequest\n\nrouter = APIRouter()\nlimiter = Limiter(key_func=get_remote_address)\n\n\n@router.post("/login", response_model=TokenResponse)\n@limiter.limit(f"{settings.AUTH_RATE_LIMIT_PER_MINUTE}/minute")\nasync def login(request: Request, data: LoginRequest, db: AsyncSession = Depends(get_db)):\n    result = await db.execute(\n        select(User).where(User.username == data.username)\n    )\n    user = result.scalar_one_or_none()\n\n    if not user:\n        raise HTTPException(status_code=401, detail="Credenciales inválidas")\n\n    # Check lockout\n    if user.locked_until and user.locked_until > datetime.now(timezone.utc):\n        remaining = (user.locked_until - datetime.now(timezone.utc)).seconds // 60\n        raise HTTPException(\n            status_code=423,\n            detail=f"Cuenta bloqueada. Intente en {remaining} minutos.",\n        )\n\n    if not verify_password(data.password, user.hashed_password):\n        user.failed_login_attempts += 1\n        if user.failed_login_attempts >= settings.MAX_LOGIN_ATTEMPTS:\n            user.locked_until = datetime.now(timezone.utc) + timedelta(\n                minutes=settings.LOCKOUT_DURATION_MINUTES\n            )\n        await db.commit()\n        raise HTTPException(status_code=401, detail="Credenciales inválidas")\n\n    if not user.is_active:\n        raise HTTPException(status_code=403, detail="Usuario inactivo")\n\n    # Reset failed attempts\n    user.failed_login_attempts = 0\n    user.locked_until = None\n    user.last_login = datetime.now(timezone.utc)\n    await db.commit()\n    await db.refresh(user)\n\n    access_token = create_access_token({"sub": str(user.id), "role": user.role})\n    refresh_token = create_refresh_token({"sub": str(user.id)})\n\n    return TokenResponse(\n        access_token=access_token,\n        refresh_token=refresh_token,\n        user=UserResponse.model_validate(user),\n    )\n\n\n@router.post("/register", response_model=UserResponse, status_code=201)\n@limiter.limit("5/minute")\nasync def register(\n    request: Request,\n    data: UserCreate,\n    db: AsyncSession = Depends(get_db),\n    current_user: User = Depends(get_current_user),\n):\n    if current_user.role != "admin":\n        raise HTTPException(status_code=403, detail="Solo administradores pueden crear usuarios")\n\n    # Check existing\n    result = await db.execute(\n        select(User).where((User.email == data.email) | (User.username == data.username))\n    )\n    if result.scalar_one_or_none():\n        raise HTTPException(status_code=400, detail="Email o usuario ya existe")\n\n    user = User(\n        email=data.email,\n        username=data.username,\n        full_name=data.full_name,\n        role=data.role,\n        hashed_password=hash_password(data.password),\n    )\n    db.add(user)\n    await db.commit()\n    await db.refresh(user)\n    return UserResponse.model_validate(user)\n\n\n@router.post("/refresh", response_model=TokenResponse)\nasync def refresh_token(data: RefreshTokenRequest, db: AsyncSession = Depends(get_db)):\n    payload = decode_token(data.refresh_token)\n    if payload.get("type") != "refresh":\n        raise HTTPException(status_code=401, detail="Token inválido")\n\n    result = await db.execute(select(User).where(User.id == int(payload["sub"])))\n    user = result.scalar_one_or_none()\n    if not user or not user.is_active:\n        raise HTTPException(status_code=401, detail="Usuario no encontrado")\n\n    access_token = create_access_token({"sub": str(user.id), "role": user.role})\n    new_refresh = create_refresh_token({"sub": str(user.id)})\n\n    return TokenResponse(\n        access_token=access_token,\n        refresh_token=new_refresh,\n        user=UserResponse.model_validate(user),\n    )\n\n\n@router.get("/me", response_model=UserResponse)\nasync def get_me(current_user: User = Depends(get_current_user)):\n    return UserResponse.model_validate(current_user)\n'

FILES[r"backend\\app\\routers\\employees.py"] = 'from fastapi import APIRouter, Depends, HTTPException, Query\nfrom sqlalchemy.ext.asyncio import AsyncSession\nfrom sqlalchemy import select, func\nfrom typing import List, Optional\n\nfrom app.core.database import get_db\nfrom app.core.security import get_current_user\nfrom app.models.employee import Employee\nfrom app.models.user import User\nfrom app.schemas.employee import EmployeeCreate, EmployeeUpdate, EmployeeResponse\n\nrouter = APIRouter()\n\n\ndef generate_employee_code(db_count: int) -> str:\n    return f"EMP-{str(db_count + 1).zfill(5)}"\n\n\n@router.get("/", response_model=List[EmployeeResponse])\nasync def list_employees(\n    skip: int = Query(0, ge=0),\n    limit: int = Query(50, ge=1, le=200),\n    search: Optional[str] = None,\n    department: Optional[str] = None,\n    db: AsyncSession = Depends(get_db),\n    current_user: User = Depends(get_current_user),\n):\n    query = select(Employee).where(Employee.is_active == True)\n    if search:\n        query = query.where(\n            (Employee.first_name.ilike(f"%{search}%")) |\n            (Employee.last_name.ilike(f"%{search}%")) |\n            (Employee.document_id.ilike(f"%{search}%")) |\n            (Employee.employee_code.ilike(f"%{search}%"))\n        )\n    if department:\n        query = query.where(Employee.department == department)\n\n    result = await db.execute(query.offset(skip).limit(limit))\n    return [EmployeeResponse.model_validate(e) for e in result.scalars().all()]\n\n\n@router.post("/", response_model=EmployeeResponse, status_code=201)\nasync def create_employee(\n    data: EmployeeCreate,\n    db: AsyncSession = Depends(get_db),\n    current_user: User = Depends(get_current_user),\n):\n    # Check duplicate document\n    result = await db.execute(select(Employee).where(Employee.document_id == data.document_id))\n    if result.scalar_one_or_none():\n        raise HTTPException(status_code=400, detail="Documento ya registrado")\n\n    # Generate code\n    count_result = await db.execute(select(func.count(Employee.id)))\n    count = count_result.scalar()\n\n    employee = Employee(**data.model_dump(), employee_code=generate_employee_code(count))\n    db.add(employee)\n    await db.commit()\n    await db.refresh(employee)\n    return EmployeeResponse.model_validate(employee)\n\n\n@router.get("/{employee_id}", response_model=EmployeeResponse)\nasync def get_employee(\n    employee_id: int,\n    db: AsyncSession = Depends(get_db),\n    current_user: User = Depends(get_current_user),\n):\n    result = await db.execute(select(Employee).where(Employee.id == employee_id))\n    employee = result.scalar_one_or_none()\n    if not employee:\n        raise HTTPException(status_code=404, detail="Empleado no encontrado")\n    return EmployeeResponse.model_validate(employee)\n\n\n@router.patch("/{employee_id}", response_model=EmployeeResponse)\nasync def update_employee(\n    employee_id: int,\n    data: EmployeeUpdate,\n    db: AsyncSession = Depends(get_db),\n    current_user: User = Depends(get_current_user),\n):\n    result = await db.execute(select(Employee).where(Employee.id == employee_id))\n    employee = result.scalar_one_or_none()\n    if not employee:\n        raise HTTPException(status_code=404, detail="Empleado no encontrado")\n\n    for field, value in data.model_dump(exclude_unset=True).items():\n        setattr(employee, field, value)\n\n    await db.commit()\n    await db.refresh(employee)\n    return EmployeeResponse.model_validate(employee)\n\n\n@router.delete("/{employee_id}", status_code=204)\nasync def deactivate_employee(\n    employee_id: int,\n    db: AsyncSession = Depends(get_db),\n    current_user: User = Depends(get_current_user),\n):\n    result = await db.execute(select(Employee).where(Employee.id == employee_id))\n    employee = result.scalar_one_or_none()\n    if not employee:\n        raise HTTPException(status_code=404, detail="Empleado no encontrado")\n    employee.is_active = False\n    await db.commit()\n'

FILES[r"backend\\app\\routers\\payroll.py"] = 'from fastapi import APIRouter, Depends, HTTPException, Query\nfrom sqlalchemy.ext.asyncio import AsyncSession\nfrom sqlalchemy import select\nfrom typing import List, Optional\nfrom decimal import Decimal\n\nfrom app.core.database import get_db\nfrom app.core.security import get_current_user, require_role\nfrom app.models.payroll import Payroll, PayrollStatus\nfrom app.models.employee import Employee\nfrom app.models.user import User\nfrom app.schemas.payroll import PayrollCreate, PayrollResponse\n\nrouter = APIRouter()\n\n# Panama SS rates\nSS_EMPLOYEE_RATE = Decimal("0.0975")   # 9.75%\nINCOME_TAX_BASE = Decimal("0.15")      # simplified 15% above threshold\nOVERTIME_RATE = Decimal("1.5")\n\n\ndef calculate_payroll(employee: Employee, data: PayrollCreate) -> dict:\n    base = employee.base_salary\n    overtime_hourly = (base / Decimal("160")) * OVERTIME_RATE\n    overtime_amount = overtime_hourly * data.overtime_hours\n    gross = base + overtime_amount + data.bonuses\n\n    social_security = gross * SS_EMPLOYEE_RATE\n    income_tax = gross * INCOME_TAX_BASE if gross > Decimal("800") else Decimal("0")\n    total_deductions = social_security + income_tax + data.other_deductions\n    net = gross - total_deductions\n\n    return {\n        "base_salary": base,\n        "overtime_hours": data.overtime_hours,\n        "overtime_amount": overtime_amount,\n        "bonuses": data.bonuses,\n        "gross_salary": gross,\n        "social_security": social_security.quantize(Decimal("0.01")),\n        "income_tax": income_tax.quantize(Decimal("0.01")),\n        "other_deductions": data.other_deductions,\n        "total_deductions": total_deductions.quantize(Decimal("0.01")),\n        "net_salary": net.quantize(Decimal("0.01")),\n    }\n\n\n@router.get("/", response_model=List[PayrollResponse])\nasync def list_payrolls(\n    skip: int = Query(0, ge=0),\n    limit: int = Query(50, ge=1, le=200),\n    employee_id: Optional[int] = None,\n    status: Optional[PayrollStatus] = None,\n    db: AsyncSession = Depends(get_db),\n    current_user: User = Depends(get_current_user),\n):\n    query = select(Payroll)\n    if employee_id:\n        query = query.where(Payroll.employee_id == employee_id)\n    if status:\n        query = query.where(Payroll.status == status)\n    result = await db.execute(query.offset(skip).limit(limit).order_by(Payroll.created_at.desc()))\n    return [PayrollResponse.model_validate(p) for p in result.scalars().all()]\n\n\n@router.post("/", response_model=PayrollResponse, status_code=201)\nasync def create_payroll(\n    data: PayrollCreate,\n    db: AsyncSession = Depends(get_db),\n    current_user: User = Depends(get_current_user),\n):\n    result = await db.execute(select(Employee).where(Employee.id == data.employee_id, Employee.is_active == True))\n    employee = result.scalar_one_or_none()\n    if not employee:\n        raise HTTPException(status_code=404, detail="Empleado no encontrado")\n\n    calcs = calculate_payroll(employee, data)\n    payroll = Payroll(\n        employee_id=data.employee_id,\n        period_start=data.period_start,\n        period_end=data.period_end,\n        notes=data.notes,\n        created_by=current_user.id,\n        **calcs,\n    )\n    db.add(payroll)\n    await db.commit()\n    await db.refresh(payroll)\n    return PayrollResponse.model_validate(payroll)\n\n\n@router.patch("/{payroll_id}/approve", response_model=PayrollResponse)\nasync def approve_payroll(\n    payroll_id: int,\n    db: AsyncSession = Depends(get_db),\n    current_user: User = Depends(require_role("admin")),\n):\n    result = await db.execute(select(Payroll).where(Payroll.id == payroll_id))\n    payroll = result.scalar_one_or_none()\n    if not payroll:\n        raise HTTPException(status_code=404, detail="Nómina no encontrada")\n    if payroll.status != PayrollStatus.borrador:\n        raise HTTPException(status_code=400, detail="Solo se puede aprobar una nómina en borrador")\n    payroll.status = PayrollStatus.procesado\n    await db.commit()\n    await db.refresh(payroll)\n    return PayrollResponse.model_validate(payroll)\n'

FILES[r"backend\\app\\routers\\users.py"] = 'from fastapi import APIRouter, Depends, HTTPException\nfrom sqlalchemy.ext.asyncio import AsyncSession\nfrom sqlalchemy import select\nfrom typing import List\n\nfrom app.core.database import get_db\nfrom app.core.security import get_current_user, require_role\nfrom app.models.user import User\nfrom app.schemas.user import UserResponse, UserCreate\nfrom app.core.security import hash_password\n\nrouter = APIRouter()\n\n\n@router.get("/", response_model=List[UserResponse])\nasync def list_users(\n    db: AsyncSession = Depends(get_db),\n    current_user: User = Depends(require_role("admin")),\n):\n    result = await db.execute(select(User))\n    return [UserResponse.model_validate(u) for u in result.scalars().all()]\n\n\n@router.get("/{user_id}", response_model=UserResponse)\nasync def get_user(\n    user_id: int,\n    db: AsyncSession = Depends(get_db),\n    current_user: User = Depends(require_role("admin")),\n):\n    result = await db.execute(select(User).where(User.id == user_id))\n    user = result.scalar_one_or_none()\n    if not user:\n        raise HTTPException(status_code=404, detail="Usuario no encontrado")\n    return UserResponse.model_validate(user)\n\n\n@router.patch("/{user_id}/toggle-active", response_model=UserResponse)\nasync def toggle_user_active(\n    user_id: int,\n    db: AsyncSession = Depends(get_db),\n    current_user: User = Depends(require_role("admin")),\n):\n    result = await db.execute(select(User).where(User.id == user_id))\n    user = result.scalar_one_or_none()\n    if not user:\n        raise HTTPException(status_code=404, detail="Usuario no encontrado")\n    if user.id == current_user.id:\n        raise HTTPException(status_code=400, detail="No puedes desactivarte a ti mismo")\n    user.is_active = not user.is_active\n    await db.commit()\n    await db.refresh(user)\n    return UserResponse.model_validate(user)\n'

