FILES[r"backend\\app\\schemas\\employee.py"] = 'from pydantic import BaseModel, EmailStr\nfrom typing import Optional\nfrom datetime import date, datetime\nfrom decimal import Decimal\nfrom app.models.employee import EmployeeStatus, ContractType\n\n\nclass EmployeeBase(BaseModel):\n    first_name: str\n    last_name: str\n    document_id: str\n    email: Optional[EmailStr] = None\n    phone: Optional[str] = None\n    position: str\n    department: str\n    base_salary: Decimal\n    hire_date: date\n    contract_type: ContractType = ContractType.indefinido\n\n\nclass EmployeeCreate(EmployeeBase):\n    pass\n\n\nclass EmployeeUpdate(BaseModel):\n    first_name: Optional[str] = None\n    last_name: Optional[str] = None\n    email: Optional[EmailStr] = None\n    phone: Optional[str] = None\n    position: Optional[str] = None\n    department: Optional[str] = None\n    base_salary: Optional[Decimal] = None\n    contract_type: Optional[ContractType] = None\n    status: Optional[EmployeeStatus] = None\n\n\nclass EmployeeResponse(EmployeeBase):\n    id: int\n    employee_code: str\n    status: EmployeeStatus\n    is_active: bool\n    created_at: datetime\n\n    model_config = {"from_attributes": True}\n'

FILES[r"backend\\app\\schemas\\payroll.py"] = 'from pydantic import BaseModel\nfrom typing import Optional\nfrom datetime import date, datetime\nfrom decimal import Decimal\nfrom app.models.payroll import PayrollStatus\n\n\nclass PayrollCreate(BaseModel):\n    employee_id: int\n    period_start: date\n    period_end: date\n    overtime_hours: Decimal = Decimal("0")\n    bonuses: Decimal = Decimal("0")\n    other_deductions: Decimal = Decimal("0")\n    notes: Optional[str] = None\n\n\nclass PayrollResponse(BaseModel):\n    id: int\n    employee_id: int\n    period_start: date\n    period_end: date\n    base_salary: Decimal\n    overtime_hours: Decimal\n    overtime_amount: Decimal\n    bonuses: Decimal\n    gross_salary: Decimal\n    social_security: Decimal\n    income_tax: Decimal\n    other_deductions: Decimal\n    total_deductions: Decimal\n    net_salary: Decimal\n    status: PayrollStatus\n    payment_date: Optional[date]\n    notes: Optional[str]\n    created_at: datetime\n\n    model_config = {"from_attributes": True}\n'

FILES[r"backend\\app\\schemas\\user.py"] = 'from pydantic import BaseModel, EmailStr, field_validator\nfrom typing import Optional\nfrom datetime import datetime\nfrom app.models.user import UserRole\nimport re\n\n\nclass UserBase(BaseModel):\n    email: EmailStr\n    username: str\n    full_name: str\n    role: UserRole = UserRole.operador_nomina\n\n\nclass UserCreate(UserBase):\n    password: str\n\n    @field_validator("password")\n    @classmethod\n    def validate_password(cls, v):\n        if len(v) < 8:\n            raise ValueError("La contraseña debe tener al menos 8 caracteres")\n        if not re.search(r"[A-Z]", v):\n            raise ValueError("Debe contener al menos una mayúscula")\n        if not re.search(r"[0-9]", v):\n            raise ValueError("Debe contener al menos un número")\n        return v\n\n\nclass UserResponse(UserBase):\n    id: int\n    is_active: bool\n    last_login: Optional[datetime] = None\n    created_at: datetime\n\n    model_config = {"from_attributes": True}\n\n\nclass LoginRequest(BaseModel):\n    username: str\n    password: str\n\n\nclass TokenResponse(BaseModel):\n    access_token: str\n    refresh_token: str\n    token_type: str = "bearer"\n    user: UserResponse\n\n\nclass RefreshTokenRequest(BaseModel):\n    refresh_token: str\n\n\nclass ChangePasswordRequest(BaseModel):\n    current_password: str\n    new_password: str\n\n    @field_validator("new_password")\n    @classmethod\n    def validate_new_password(cls, v):\n        if len(v) < 8:\n            raise ValueError("La contraseña debe tener al menos 8 caracteres")\n        if not re.search(r"[A-Z]", v):\n            raise ValueError("Debe contener al menos una mayúscula")\n        if not re.search(r"[0-9]", v):\n            raise ValueError("Debe contener al menos un número")\n        return v\n'

