FILES[r"frontend\\src\\App.jsx"] = 'import { BrowserRouter, Routes, Route, Navigate } from \'react-router-dom\'\nimport { ThemeProvider, CssBaseline } from \'@mui/material\'\nimport { theme } from \'./theme/theme\'\nimport LoginPage from \'./pages/LoginPage\'\nimport DashboardPage from \'./pages/DashboardPage\'\nimport EmployeesPage from \'./pages/EmployeesPage\'\nimport PayrollPage from \'./pages/PayrollPage\'\nimport UsersPage from \'./pages/UsersPage\'\nimport AppLayout from \'./components/layout/AppLayout\'\nimport ProtectedRoute from \'./components/auth/ProtectedRoute\'\n\nexport default function App() {\n  return (\n    <ThemeProvider theme={theme}>\n      <CssBaseline />\n      <BrowserRouter>\n        <Routes>\n          <Route path="/login" element={<LoginPage />} />\n          <Route path="/" element={<ProtectedRoute><AppLayout /></ProtectedRoute>}>\n            <Route index element={<Navigate to="/dashboard" replace />} />\n            <Route path="dashboard" element={<DashboardPage />} />\n            <Route path="employees" element={<EmployeesPage />} />\n            <Route path="payroll" element={<PayrollPage />} />\n            <Route path="users" element={\n              <ProtectedRoute adminOnly><UsersPage /></ProtectedRoute>\n            } />\n          </Route>\n          <Route path="*" element={<Navigate to="/dashboard" replace />} />\n        </Routes>\n      </BrowserRouter>\n    </ThemeProvider>\n  )\n}\n'

FILES[r"frontend\\src\\components\\auth\\ProtectedRoute.jsx"] = 'import { Navigate } from \'react-router-dom\'\nimport { useAuthStore } from \'../../context/authStore\'\n\nexport default function ProtectedRoute({ children, adminOnly }) {\n  const { isAuthenticated, user } = useAuthStore()\n\n  if (!isAuthenticated) return <Navigate to="/login" replace />\n  if (adminOnly && user?.role !== \'admin\') return <Navigate to="/dashboard" replace />\n\n  return <>{children}</>\n}\n'

FILES[r"frontend\\src\\components\\layout\\AppLayout.jsx"] = 'import { useState } from \'react\'\nimport {\n  Box, Drawer, List, ListItemButton, ListItemIcon, ListItemText,\n  Typography, Avatar, Divider, IconButton, Tooltip,\n  useMediaQuery, useTheme as useMuiTheme,\n} from \'@mui/material\'\nimport {\n  DashboardOutlined, PeopleOutlined, ReceiptLongOutlined,\n  PersonOutlined, Menu as MenuIcon, LogoutOutlined,\n  LockOutlined, ChevronLeft,\n} from \'@mui/icons-material\'\nimport { useNavigate, useLocation, Outlet } from \'react-router-dom\'\nimport { useAuthStore } from \'../../context/authStore\'\nimport { COLORS } from \'../../theme/theme\'\n\nconst DRAWER_WIDTH = 240\nconst DRAWER_COLLAPSED = 68\n\nconst navItems = [\n  { label: \'Dashboard\',  icon: <DashboardOutlined />,    path: \'/dashboard\' },\n  { label: \'Empleados\',  icon: <PeopleOutlined />,        path: \'/employees\' },\n  { label: \'Nóminas\',    icon: <ReceiptLongOutlined />,   path: \'/payroll\' },\n  { label: \'Usuarios\',   icon: <PersonOutlined />,        path: \'/users\', adminOnly: true },\n]\n\nexport default function AppLayout() {\n  const navigate = useNavigate()\n  const location = useLocation()\n  const { user, logout } = useAuthStore()\n  const muiTheme = useMuiTheme()\n  const isMobile = useMediaQuery(muiTheme.breakpoints.down(\'md\'))\n  const [collapsed, setCollapsed] = useState(false)\n  const [mobileOpen, setMobileOpen] = useState(false)\n\n  const drawerWidth = collapsed ? DRAWER_COLLAPSED : DRAWER_WIDTH\n\n  const handleLogout = () => {\n    logout()\n    navigate(\'/login\')\n  }\n\n  const filtered = navItems.filter(item => !item.adminOnly || user?.role === \'admin\')\n\n  const drawerContent = (\n    <Box sx={{ height: \'100%\', display: \'flex\', flexDirection: \'column\' }}>\n      {/* Logo */}\n      <Box sx={{\n        p: 2,\n        display: \'flex\',\n        alignItems: \'center\',\n        justifyContent: collapsed ? \'center\' : \'space-between\',\n        minHeight: 64,\n      }}>\n        {!collapsed && (\n          <Box sx={{ display: \'flex\', alignItems: \'center\', gap: 1.5 }}>\n            <Box sx={{\n              width: 30, height: 30, borderRadius: \'8px\',\n              background: COLORS.accent,\n              display: \'flex\', alignItems: \'center\', justifyContent: \'center\', flexShrink: 0,\n            }}>\n              <LockOutlined sx={{ color: COLORS.black, fontSize: 15 }} />\n            </Box>\n            <Typography sx={{ fontFamily: \'"Syne", sans-serif\', fontWeight: 700, fontSize: \'1rem\', color: COLORS.textPrimary }}>\n              PayApp\n            </Typography>\n          </Box>\n        )}\n        {collapsed && (\n          <Box sx={{ width: 30, height: 30, borderRadius: \'8px\', background: COLORS.accent, display: \'flex\', alignItems: \'center\', justifyContent: \'center\' }}>\n            <LockOutlined sx={{ color: COLORS.black, fontSize: 15 }} />\n          </Box>\n        )}\n        {!isMobile && (\n          <IconButton size="small" onClick={() => setCollapsed(!collapsed)} sx={{ color: COLORS.textMuted, \'&:hover\': { color: COLORS.textPrimary } }}>\n            {collapsed ? <MenuIcon fontSize="small" /> : <ChevronLeft fontSize="small" />}\n          </IconButton>\n        )}\n      </Box>\n\n      <Divider />\n\n      {/* Nav items */}\n      <List sx={{ flex: 1, pt: 1, px: 0 }}>\n        {filtered.map((item) => {\n          const active = location.pathname.startsWith(item.path)\n          return (\n            <Tooltip key={item.path} title={collapsed ? item.label : \'\'} placement="right">\n              <ListItemButton\n                selected={active}\n                onClick={() => { navigate(item.path); if (isMobile) setMobileOpen(false) }}\n                sx={{ mx: 1, px: collapsed ? 1 : 1.5, py: 1, justifyContent: collapsed ? \'center\' : \'flex-start\', minHeight: 42 }}\n              >\n                <ListItemIcon sx={{ minWidth: collapsed ? 0 : 36, color: active ? COLORS.accent : COLORS.textSecondary }}>\n                  {item.icon}\n                </ListItemIcon>\n                {!collapsed && (\n                  <ListItemText\n                    primary={item.label}\n                    primaryTypographyProps={{\n                      fontSize: \'0.875rem\',\n                      fontWeight: active ? 600 : 400,\n                      color: active ? COLORS.accent : COLORS.textPrimary,\n                    }}\n                  />\n                )}\n              </ListItemButton>\n            </Tooltip>\n          )\n        })}\n      </List>\n\n      <Divider />\n\n      {/* User info */}\n      <Box sx={{ p: 1.5 }}>\n        {!collapsed ? (\n          <Box sx={{ display: \'flex\', alignItems: \'center\', gap: 1.5, p: 1.5, borderRadius: 2, background: COLORS.black }}>\n            <Avatar sx={{ width: 32, height: 32, bgcolor: COLORS.accentMuted, color: COLORS.accent, fontSize: \'0.85rem\', fontWeight: 700 }}>\n              {user?.full_name?.[0]?.toUpperCase()}\n            </Avatar>\n            <Box sx={{ flex: 1, overflow: \'hidden\' }}>\n              <Typography variant="body2" sx={{ fontWeight: 600, fontSize: \'0.8rem\', color: COLORS.textPrimary, overflow: \'hidden\', textOverflow: \'ellipsis\', whiteSpace: \'nowrap\' }}>\n                {user?.full_name}\n              </Typography>\n              <Typography variant="caption" sx={{ color: COLORS.textMuted, fontSize: \'0.7rem\', textTransform: \'capitalize\' }}>\n                {user?.role?.replace(\'_\', \' \')}\n              </Typography>\n            </Box>\n            <Tooltip title="Cerrar sesión">\n              <IconButton size="small" onClick={handleLogout} sx={{ color: COLORS.textMuted, \'&:hover\': { color: COLORS.error } }}>\n                <LogoutOutlined fontSize="small" />\n              </IconButton>\n            </Tooltip>\n          </Box>\n        ) : (\n          <Box sx={{ display: \'flex\', flexDirection: \'column\', alignItems: \'center\', gap: 1 }}>\n            <Avatar sx={{ width: 30, height: 30, bgcolor: COLORS.accentMuted, color: COLORS.accent, fontSize: \'0.8rem\', fontWeight: 700 }}>\n              {user?.full_name?.[0]?.toUpperCase()}\n            </Avatar>\n            <Tooltip title="Cerrar sesión" placement="right">\n              <IconButton size="small" onClick={handleLogout} sx={{ color: COLORS.textMuted, \'&:hover\': { color: COLORS.error } }}>\n                <LogoutOutlined sx={{ fontSize: 16 }} />\n              </IconButton>\n            </Tooltip>\n          </Box>\n        )}\n      </Box>\n    </Box>\n  )\n\n  return (\n    <Box sx={{ display: \'flex\', minHeight: \'100vh\', background: COLORS.black }}>\n      {/* Mobile toggle button */}\n      {isMobile && (\n        <Box sx={{ position: \'fixed\', top: 12, left: 12, zIndex: 1300 }}>\n          <IconButton\n            onClick={() => setMobileOpen(!mobileOpen)}\n            sx={{ color: COLORS.textPrimary, bgcolor: COLORS.cardBg, border: `1px solid ${COLORS.borderSubtle}` }}\n          >\n            <MenuIcon />\n          </IconButton>\n        </Box>\n      )}\n\n      {/* Desktop sidebar */}\n      {!isMobile && (\n        <Drawer\n          variant="permanent"\n          sx={{\n            width: drawerWidth,\n            flexShrink: 0,\n            transition: \'width 0.2s ease\',\n            \'& .MuiDrawer-paper\': { width: drawerWidth, overflowX: \'hidden\', transition: \'width 0.2s ease\' },\n          }}\n        >\n          {drawerContent}\n        </Drawer>\n      )}\n\n      {/* Mobile sidebar */}\n      {isMobile && (\n        <Drawer open={mobileOpen} onClose={() => setMobileOpen(false)} sx={{ \'& .MuiDrawer-paper\': { width: DRAWER_WIDTH } }}>\n          {drawerContent}\n        </Drawer>\n      )}\n\n      {/* Main content area */}\n      <Box sx={{ flex: 1, minWidth: 0, display: \'flex\', flexDirection: \'column\' }}>\n        <Box sx={{ flex: 1, p: { xs: 2, sm: 3, md: 4 }, pt: { xs: 7, md: 4 } }}>\n          <Outlet />\n        </Box>\n      </Box>\n    </Box>\n  )\n}\n'

FILES[r"frontend\\src\\context\\authStore.js"] = "import { create } from 'zustand'\nimport { persist } from 'zustand/middleware'\n\nexport const useAuthStore = create(\n  persist(\n    (set) => ({\n      user: null,\n      accessToken: null,\n      refreshToken: null,\n      isAuthenticated: false,\n      setTokens: (access, refresh) =>\n        set({ accessToken: access, refreshToken: refresh, isAuthenticated: true }),\n      setUser: (user) => set({ user }),\n      logout: () =>\n        set({ user: null, accessToken: null, refreshToken: null, isAuthenticated: false }),\n    }),\n    {\n      name: 'payapp-auth',\n      partialize: (state) => ({\n        accessToken: state.accessToken,\n        refreshToken: state.refreshToken,\n        user: state.user,\n        isAuthenticated: state.isAuthenticated,\n      }),\n    }\n  )\n)\n"

FILES[r"frontend\\src\\main.jsx"] = "import React from 'react'\nimport ReactDOM from 'react-dom/client'\nimport App from './App'\n\nReactDOM.createRoot(document.getElementById('root')).render(\n  <React.StrictMode>\n    <App />\n  </React.StrictMode>\n)\n"

FILES[r"frontend\\src\\pages\\DashboardPage.jsx"] = 'import { useEffect, useState } from \'react\'\nimport {\n  Box, Typography, Grid, Card, CardContent, Chip,\n  LinearProgress, Skeleton,\n} from \'@mui/material\'\nimport {\n  PeopleOutlined, ReceiptLongOutlined, AttachMoneyOutlined, TrendingUpOutlined,\n} from \'@mui/icons-material\'\nimport { AreaChart, Area, XAxis, YAxis, CartesianGrid, Tooltip, ResponsiveContainer } from \'recharts\'\nimport { useAuthStore } from \'../context/authStore\'\nimport { employeesApi, payrollApi } from \'../services/api\'\nimport { COLORS } from \'../theme/theme\'\n\nconst mockChartData = [\n  { month: \'Ene\', nomina: 45000 },\n  { month: \'Feb\', nomina: 47200 },\n  { month: \'Mar\', nomina: 46800 },\n  { month: \'Abr\', nomina: 49100 },\n  { month: \'May\', nomina: 51300 },\n  { month: \'Jun\', nomina: 50900 },\n  { month: \'Jul\', nomina: 53200 },\n]\n\nfunction StatCard({ title, value, subtitle, icon, accent, progress }) {\n  return (\n    <Card sx={{ height: \'100%\' }}>\n      <CardContent sx={{ p: 3 }}>\n        <Box sx={{ display: \'flex\', justifyContent: \'space-between\', alignItems: \'flex-start\', mb: 2 }}>\n          <Box sx={{\n            width: 40, height: 40, borderRadius: \'10px\',\n            background: accent ? COLORS.accentMuted : \'rgba(255,255,255,0.06)\',\n            display: \'flex\', alignItems: \'center\', justifyContent: \'center\',\n            color: accent ? COLORS.accent : COLORS.textSecondary,\n          }}>\n            {icon}\n          </Box>\n          {progress !== undefined && (\n            <Typography variant="caption" sx={{ color: COLORS.accent, fontFamily: \'"DM Mono", monospace\', fontSize: \'0.75rem\' }}>\n              {progress}%\n            </Typography>\n          )}\n        </Box>\n        <Typography variant="h4" sx={{ color: COLORS.textPrimary, mb: 0.5, fontWeight: 700 }}>\n          {value}\n        </Typography>\n        <Typography variant="caption" sx={{ color: COLORS.textSecondary, letterSpacing: \'0.05em\', textTransform: \'uppercase\', fontSize: \'0.7rem\' }}>\n          {title}\n        </Typography>\n        <Typography variant="body2" sx={{ color: COLORS.textMuted, mt: 0.5, fontSize: \'0.8rem\' }}>\n          {subtitle}\n        </Typography>\n        {progress !== undefined && (\n          <LinearProgress variant="determinate" value={progress} sx={{ mt: 2, height: 3 }} />\n        )}\n      </CardContent>\n    </Card>\n  )\n}\n\nfunction CustomTooltip({ active, payload, label }) {\n  if (active && payload?.length) {\n    return (\n      <Box sx={{ bgcolor: COLORS.cardBg, border: `1px solid ${COLORS.borderSubtle}`, p: 1.5, borderRadius: 2 }}>\n        <Typography variant="caption" sx={{ color: COLORS.textSecondary, display: \'block\', mb: 0.5 }}>{label}</Typography>\n        <Typography variant="body2" sx={{ color: COLORS.accent, fontFamily: \'"DM Mono", monospace\', fontWeight: 600 }}>\n          ${payload[0].value.toLocaleString()}\n        </Typography>\n      </Box>\n    )\n  }\n  return null\n}\n\nexport default function DashboardPage() {\n  const { user } = useAuthStore()\n  const [loading, setLoading] = useState(true)\n  const [stats, setStats] = useState({ employees: 0, payrolls: 0, totalNomina: 0 })\n\n  useEffect(() => {\n    const load = async () => {\n      try {\n        const [empRes, payRes] = await Promise.all([\n          employeesApi.list({ limit: 200 }),\n          payrollApi.list({ limit: 200 }),\n        ])\n        const payrolls = payRes.data || []\n        const total = payrolls.reduce((sum, p) => sum + parseFloat(p.net_salary || 0), 0)\n        setStats({\n          employees: empRes.data?.length || 0,\n          payrolls: payrolls.length,\n          totalNomina: total,\n        })\n      } catch { /* use defaults */ }\n      finally { setLoading(false) }\n    }\n    load()\n  }, [])\n\n  return (\n    <Box>\n      {/* Header */}\n      <Box sx={{ mb: 5 }}>\n        <Box sx={{ display: \'flex\', alignItems: \'center\', gap: 2, mb: 1 }}>\n          <Typography variant="h3" sx={{ color: COLORS.textPrimary, lineHeight: 1 }}>\n            Bienvenido,\n          </Typography>\n          <Typography variant="h3" sx={{ color: COLORS.accent, lineHeight: 1 }}>\n            {user?.full_name?.split(\' \')[0]}.\n          </Typography>\n        </Box>\n        <Typography variant="body2" sx={{ color: COLORS.textSecondary }}>\n          Resumen del sistema de nómina · {new Date().toLocaleDateString(\'es-PA\', { weekday: \'long\', year: \'numeric\', month: \'long\', day: \'numeric\' })}\n        </Typography>\n      </Box>\n\n      {/* Stat cards */}\n      <Grid container spacing={2.5} sx={{ mb: 4 }}>\n        {[\n          { title: \'Empleados activos\',   value: stats.employees, subtitle: \'En nómina actualmente\', icon: <PeopleOutlined fontSize="small" />, accent: true, progress: 82 },\n          { title: \'Nóminas generadas\',   value: stats.payrolls,  subtitle: \'Período actual\',         icon: <ReceiptLongOutlined fontSize="small" /> },\n          { title: \'Total nómina\',        value: `$${stats.totalNomina.toLocaleString(\'es-PA\', { minimumFractionDigits: 2 })}`, subtitle: \'Salarios netos procesados\', icon: <AttachMoneyOutlined fontSize="small" />, accent: true },\n          { title: \'Crecimiento\',         value: \'+4.5%\',         subtitle: \'Respecto al mes anterior\', icon: <TrendingUpOutlined fontSize="small" /> },\n        ].map((card) => (\n          <Grid item xs={12} sm={6} lg={3} key={card.title}>\n            {loading\n              ? <Skeleton variant="rounded" height={140} />\n              : <StatCard {...card} />\n            }\n          </Grid>\n        ))}\n      </Grid>\n\n      {/* Chart */}\n      <Card>\n        <CardContent sx={{ p: 3 }}>\n          <Box sx={{ display: \'flex\', justifyContent: \'space-between\', alignItems: \'center\', mb: 3 }}>\n            <Box>\n              <Typography variant="h6" sx={{ color: COLORS.textPrimary, mb: 0.25 }}>Evolución de Nómina</Typography>\n              <Typography variant="caption" sx={{ color: COLORS.textSecondary }}>Total mensual · 2025</Typography>\n            </Box>\n            <Chip label="En vivo" size="small" color="success" sx={{ fontSize: \'0.7rem\', height: 22 }} />\n          </Box>\n\n          <ResponsiveContainer width="100%" height={240}>\n            <AreaChart data={mockChartData} margin={{ top: 5, right: 5, bottom: 5, left: 0 }}>\n              <defs>\n                <linearGradient id="nomGrad" x1="0" y1="0" x2="0" y2="1">\n                  <stop offset="5%"  stopColor={COLORS.accent} stopOpacity={0.2} />\n                  <stop offset="95%" stopColor={COLORS.accent} stopOpacity={0} />\n                </linearGradient>\n              </defs>\n              <CartesianGrid strokeDasharray="3 3" stroke={COLORS.borderSubtle} vertical={false} />\n              <XAxis dataKey="month" tick={{ fill: COLORS.textMuted, fontSize: 11, fontFamily: \'"DM Mono", monospace\' }} axisLine={false} tickLine={false} />\n              <YAxis tick={{ fill: COLORS.textMuted, fontSize: 10, fontFamily: \'"DM Mono", monospace\' }} axisLine={false} tickLine={false} tickFormatter={(v) => `$${(v / 1000).toFixed(0)}k`} />\n              <Tooltip content={<CustomTooltip />} />\n              <Area type="monotone" dataKey="nomina" stroke={COLORS.accent} strokeWidth={2} fill="url(#nomGrad)"\n                dot={{ fill: COLORS.accent, r: 3, strokeWidth: 0 }} activeDot={{ r: 5, fill: COLORS.accent }} />\n            </AreaChart>\n          </ResponsiveContainer>\n        </CardContent>\n      </Card>\n    </Box>\n  )\n}\n'

FILES[r"frontend\\src\\pages\\EmployeesPage.jsx"] = 'import { useEffect, useState, useCallback } from \'react\'\nimport {\n  Box, Typography, Button, TextField, Table, TableBody, TableCell,\n  TableContainer, TableHead, TableRow, Paper, Chip, IconButton,\n  Dialog, DialogTitle, DialogContent, DialogActions, Grid,\n  InputAdornment, MenuItem, CircularProgress, Alert, Tooltip,\n} from \'@mui/material\'\nimport { AddOutlined, SearchOutlined, PersonOffOutlined, PeopleOutlined } from \'@mui/icons-material\'\nimport { employeesApi } from \'../services/api\'\nimport { COLORS } from \'../theme/theme\'\nimport { alpha } from \'@mui/material/styles\'\n\nconst CONTRACT_TYPES = [\'indefinido\', \'temporal\', \'obra_labor\']\nconst DEPARTMENTS = [\'Administración\', \'Ventas\', \'Operaciones\', \'Tecnología\', \'RRHH\', \'Finanzas\', \'Producción\']\n\nconst statusColor = {\n  activo: \'success\',\n  inactivo: \'error\',\n  suspendido: \'warning\',\n}\n\nconst emptyForm = {\n  first_name: \'\', last_name: \'\', document_id: \'\', email: \'\', phone: \'\',\n  position: \'\', department: \'\', base_salary: \'\', hire_date: \'\',\n  contract_type: \'indefinido\',\n}\n\nexport default function EmployeesPage() {\n  const [employees, setEmployees] = useState([])\n  const [loading, setLoading]     = useState(true)\n  const [search, setSearch]       = useState(\'\')\n  const [openForm, setOpenForm]   = useState(false)\n  const [saving, setSaving]       = useState(false)\n  const [error, setError]         = useState(\'\')\n  const [form, setForm]           = useState(emptyForm)\n\n  const load = useCallback(async () => {\n    setLoading(true)\n    try {\n      const res = await employeesApi.list({ search: search || undefined })\n      setEmployees(res.data)\n    } catch { /* ignore */ }\n    finally { setLoading(false) }\n  }, [search])\n\n  useEffect(() => { load() }, [load])\n\n  const handleCreate = async () => {\n    setSaving(true); setError(\'\')\n    try {\n      await employeesApi.create({ ...form, base_salary: parseFloat(form.base_salary) })\n      setOpenForm(false)\n      setForm(emptyForm)\n      load()\n    } catch (e) {\n      setError(e.response?.data?.detail || \'Error al crear empleado\')\n    } finally { setSaving(false) }\n  }\n\n  const handleDeactivate = async (id) => {\n    if (!confirm(\'¿Desactivar este empleado?\')) return\n    try { await employeesApi.deactivate(id); load() } catch { /* ignore */ }\n  }\n\n  const field = (key, value) => setForm(prev => ({ ...prev, [key]: value }))\n\n  return (\n    <Box>\n      <Box sx={{ display: \'flex\', justifyContent: \'space-between\', alignItems: \'flex-start\', mb: 4 }}>\n        <Box>\n          <Typography variant="h4" sx={{ color: COLORS.textPrimary, mb: 0.5 }}>Empleados</Typography>\n          <Typography variant="body2" sx={{ color: COLORS.textSecondary }}>{employees.length} empleados registrados</Typography>\n        </Box>\n        <Button variant="contained" startIcon={<AddOutlined />} onClick={() => setOpenForm(true)} size="small">\n          Nuevo empleado\n        </Button>\n      </Box>\n\n      <Box sx={{ mb: 3 }}>\n        <TextField\n          placeholder="Buscar por nombre, cédula o código..."\n          value={search}\n          onChange={(e) => setSearch(e.target.value)}\n          InputProps={{\n            startAdornment: (\n              <InputAdornment position="start">\n                <SearchOutlined sx={{ color: COLORS.textMuted, fontSize: 18 }} />\n              </InputAdornment>\n            ),\n          }}\n          sx={{ width: { xs: \'100%\', sm: 320 } }}\n        />\n      </Box>\n\n      <TableContainer component={Paper} sx={{ borderRadius: 3 }}>\n        <Table size="small">\n          <TableHead>\n            <TableRow>\n              {[\'Código\', \'Nombre\', \'Cédula\', \'Cargo\', \'Departamento\', \'Salario Base\', \'Contrato\', \'Estado\', \'Acciones\'].map(h => (\n                <TableCell key={h}>{h}</TableCell>\n              ))}\n            </TableRow>\n          </TableHead>\n          <TableBody>\n            {loading ? (\n              <TableRow>\n                <TableCell colSpan={9} sx={{ textAlign: \'center\', py: 4 }}>\n                  <CircularProgress size={24} sx={{ color: COLORS.accent }} />\n                </TableCell>\n              </TableRow>\n            ) : employees.length === 0 ? (\n              <TableRow>\n                <TableCell colSpan={9} sx={{ textAlign: \'center\', py: 6 }}>\n                  <PeopleOutlined sx={{ fontSize: 40, color: COLORS.textMuted, mb: 1, display: \'block\', mx: \'auto\' }} />\n                  <Typography variant="body2" sx={{ color: COLORS.textMuted }}>Sin empleados registrados</Typography>\n                </TableCell>\n              </TableRow>\n            ) : employees.map((emp) => (\n              <TableRow key={emp.id}>\n                <TableCell sx={{ fontFamily: \'"DM Mono", monospace\', fontSize: \'0.75rem\', color: COLORS.accent }}>\n                  {emp.employee_code}\n                </TableCell>\n                <TableCell sx={{ fontWeight: 500 }}>{emp.first_name} {emp.last_name}</TableCell>\n                <TableCell sx={{ fontFamily: \'"DM Mono", monospace\', fontSize: \'0.8rem\' }}>{emp.document_id}</TableCell>\n                <TableCell sx={{ fontSize: \'0.85rem\' }}>{emp.position}</TableCell>\n                <TableCell sx={{ fontSize: \'0.85rem\' }}>{emp.department}</TableCell>\n                <TableCell sx={{ fontFamily: \'"DM Mono", monospace\', fontSize: \'0.8rem\', color: COLORS.success }}>\n                  ${parseFloat(emp.base_salary).toLocaleString(\'es-PA\', { minimumFractionDigits: 2 })}\n                </TableCell>\n                <TableCell>\n                  <Chip label={emp.contract_type} size="small"\n                    sx={{ fontSize: \'0.68rem\', height: 20, bgcolor: alpha(COLORS.textMuted, 0.1), color: COLORS.textSecondary }} />\n                </TableCell>\n                <TableCell>\n                  <Chip label={emp.status} size="small" color={statusColor[emp.status] || \'default\'} />\n                </TableCell>\n                <TableCell>\n                  <Tooltip title="Desactivar">\n                    <IconButton size="small" onClick={() => handleDeactivate(emp.id)}\n                      sx={{ color: COLORS.textMuted, \'&:hover\': { color: COLORS.error } }}>\n                      <PersonOffOutlined sx={{ fontSize: 16 }} />\n                    </IconButton>\n                  </Tooltip>\n                </TableCell>\n              </TableRow>\n            ))}\n          </TableBody>\n        </Table>\n      </TableContainer>\n\n      {/* Create dialog */}\n      <Dialog open={openForm} onClose={() => setOpenForm(false)} maxWidth="sm" fullWidth PaperProps={{ sx: { borderRadius: 3 } }}>\n        <DialogTitle sx={{ fontFamily: \'"Syne", sans-serif\', pb: 1 }}>Nuevo Empleado</DialogTitle>\n        <DialogContent>\n          {error && <Alert severity="error" sx={{ mb: 2 }}>{error}</Alert>}\n          <Grid container spacing={2} sx={{ mt: 0.5 }}>\n            <Grid item xs={6}><TextField fullWidth label="Nombre"          value={form.first_name}   onChange={e => field(\'first_name\', e.target.value)} /></Grid>\n            <Grid item xs={6}><TextField fullWidth label="Apellido"        value={form.last_name}    onChange={e => field(\'last_name\', e.target.value)} /></Grid>\n            <Grid item xs={6}><TextField fullWidth label="Cédula / Doc."   value={form.document_id}  onChange={e => field(\'document_id\', e.target.value)} /></Grid>\n            <Grid item xs={6}><TextField fullWidth label="Correo"          value={form.email}        onChange={e => field(\'email\', e.target.value)} type="email" /></Grid>\n            <Grid item xs={6}><TextField fullWidth label="Teléfono"        value={form.phone}        onChange={e => field(\'phone\', e.target.value)} /></Grid>\n            <Grid item xs={6}><TextField fullWidth label="Cargo"           value={form.position}     onChange={e => field(\'position\', e.target.value)} /></Grid>\n            <Grid item xs={6}><TextField fullWidth label="Salario Base"    value={form.base_salary}  onChange={e => field(\'base_salary\', e.target.value)} type="number" /></Grid>\n            <Grid item xs={6}><TextField fullWidth label="Fecha ingreso"   value={form.hire_date}    onChange={e => field(\'hire_date\', e.target.value)} type="date" InputLabelProps={{ shrink: true }} /></Grid>\n            <Grid item xs={6}>\n              <TextField fullWidth select label="Departamento" value={form.department} onChange={e => field(\'department\', e.target.value)}>\n                {DEPARTMENTS.map(d => <MenuItem key={d} value={d}>{d}</MenuItem>)}\n              </TextField>\n            </Grid>\n            <Grid item xs={6}>\n              <TextField fullWidth select label="Tipo contrato" value={form.contract_type} onChange={e => field(\'contract_type\', e.target.value)}>\n                {CONTRACT_TYPES.map(c => <MenuItem key={c} value={c} sx={{ textTransform: \'capitalize\' }}>{c.replace(\'_\', \' \')}</MenuItem>)}\n              </TextField>\n            </Grid>\n          </Grid>\n        </DialogContent>\n        <DialogActions sx={{ px: 3, pb: 3 }}>\n          <Button onClick={() => setOpenForm(false)} disabled={saving}>Cancelar</Button>\n          <Button variant="contained" onClick={handleCreate} disabled={saving}>\n            {saving ? <CircularProgress size={18} sx={{ color: COLORS.black }} /> : \'Guardar\'}\n          </Button>\n        </DialogActions>\n      </Dialog>\n    </Box>\n  )\n}\n'

FILES[r"frontend\\src\\pages\\LoginPage.jsx"] = 'import { useState } from \'react\'\nimport {\n  Box, Button, TextField, Typography, Alert,\n  InputAdornment, IconButton, CircularProgress,\n} from \'@mui/material\'\nimport { Visibility, VisibilityOff, LockOutlined } from \'@mui/icons-material\'\nimport { useNavigate } from \'react-router-dom\'\nimport { authApi } from \'../services/api\'\nimport { useAuthStore } from \'../context/authStore\'\nimport { COLORS } from \'../theme/theme\'\n\nexport default function LoginPage() {\n  const navigate = useNavigate()\n  const { setTokens, setUser } = useAuthStore()\n  const [username, setUsername] = useState(\'\')\n  const [password, setPassword] = useState(\'\')\n  const [showPwd, setShowPwd] = useState(false)\n  const [loading, setLoading] = useState(false)\n  const [error, setError] = useState(\'\')\n\n  const handleLogin = async (e) => {\n    e.preventDefault()\n    if (!username || !password) { setError(\'Complete todos los campos\'); return }\n    setLoading(true)\n    setError(\'\')\n    try {\n      const res = await authApi.login(username, password)\n      const { access_token, refresh_token, user } = res.data\n      setTokens(access_token, refresh_token)\n      setUser(user)\n      navigate(\'/dashboard\')\n    } catch (err) {\n      const msg = err.response?.data?.detail || \'Error de conexión\'\n      setError(msg)\n    } finally {\n      setLoading(false)\n    }\n  }\n\n  return (\n    <Box sx={{\n      minHeight: \'100vh\',\n      display: \'flex\',\n      background: `radial-gradient(ellipse at 20% 50%, ${COLORS.accentMuted} 0%, transparent 60%), ${COLORS.black}`,\n    }}>\n      {/* Left panel - branding */}\n      <Box sx={{\n        flex: 1,\n        display: { xs: \'none\', md: \'flex\' },\n        flexDirection: \'column\',\n        justifyContent: \'space-between\',\n        p: 6,\n        borderRight: `1px solid ${COLORS.borderSubtle}`,\n        position: \'relative\',\n        overflow: \'hidden\',\n      }}>\n        {/* Decorative grid */}\n        <Box sx={{\n          position: \'absolute\', inset: 0, opacity: 0.04,\n          backgroundImage: \'linear-gradient(rgba(255,255,255,0.5) 1px, transparent 1px), linear-gradient(90deg, rgba(255,255,255,0.5) 1px, transparent 1px)\',\n          backgroundSize: \'48px 48px\',\n        }} />\n\n        <Box>\n          <Box sx={{ display: \'flex\', alignItems: \'center\', gap: 1.5 }}>\n            <Box sx={{\n              width: 36, height: 36, borderRadius: \'10px\',\n              background: COLORS.accent,\n              display: \'flex\', alignItems: \'center\', justifyContent: \'center\',\n            }}>\n              <LockOutlined sx={{ color: COLORS.black, fontSize: 18 }} />\n            </Box>\n            <Typography sx={{ fontFamily: \'"Syne", sans-serif\', fontWeight: 700, fontSize: \'1.1rem\', color: COLORS.textPrimary }}>\n              PayApp\n            </Typography>\n          </Box>\n        </Box>\n\n        <Box>\n          <Typography variant="h2" sx={{ color: COLORS.textPrimary, mb: 2, fontSize: { md: \'2.5rem\', lg: \'3rem\' }, lineHeight: 1.1 }}>\n            Nómina empresarial\n            <br />\n            <Box component="span" sx={{ color: COLORS.accent }}>para PYMES.</Box>\n          </Typography>\n          <Typography sx={{ color: COLORS.textSecondary, maxWidth: 380, lineHeight: 1.7 }}>\n            Gestiona empleados, calcula nóminas y mantén el control de tu empresa con total seguridad.\n          </Typography>\n        </Box>\n\n        <Box sx={{ display: \'flex\', gap: 4 }}>\n          {[[\'Empleados\', \'Gestión completa\'], [\'Nómina\', \'Cálculo automático\'], [\'Seguridad\', \'JWT + Roles\']].map(([label, sub]) => (\n            <Box key={label}>\n              <Typography sx={{ color: COLORS.accent, fontFamily: \'"DM Mono", monospace\', fontSize: \'0.7rem\', letterSpacing: \'0.1em\', mb: 0.5 }}>\n                {label.toUpperCase()}\n              </Typography>\n              <Typography variant="body2" sx={{ color: COLORS.textMuted }}>{sub}</Typography>\n            </Box>\n          ))}\n        </Box>\n      </Box>\n\n      {/* Right panel - form */}\n      <Box sx={{\n        width: { xs: \'100%\', md: 480 },\n        display: \'flex\',\n        alignItems: \'center\',\n        justifyContent: \'center\',\n        p: { xs: 3, md: 6 },\n      }}>\n        <Box sx={{ width: \'100%\', maxWidth: 360 }}>\n          {/* Mobile logo */}\n          <Box sx={{ display: { xs: \'flex\', md: \'none\' }, alignItems: \'center\', gap: 1.5, mb: 4 }}>\n            <Box sx={{ width: 32, height: 32, borderRadius: \'8px\', background: COLORS.accent, display: \'flex\', alignItems: \'center\', justifyContent: \'center\' }}>\n              <LockOutlined sx={{ color: COLORS.black, fontSize: 16 }} />\n            </Box>\n            <Typography sx={{ fontFamily: \'"Syne", sans-serif\', fontWeight: 700, color: COLORS.textPrimary }}>PayApp</Typography>\n          </Box>\n\n          <Typography variant="h4" sx={{ mb: 0.75, color: COLORS.textPrimary }}>\n            Iniciar sesión\n          </Typography>\n          <Typography variant="body2" sx={{ color: COLORS.textSecondary, mb: 4 }}>\n            Ingresa tus credenciales para continuar\n          </Typography>\n\n          {error && (\n            <Alert severity="error" sx={{ mb: 3, fontSize: \'0.85rem\' }}>\n              {error}\n            </Alert>\n          )}\n\n          <Box component="form" onSubmit={handleLogin} sx={{ display: \'flex\', flexDirection: \'column\', gap: 2.5 }}>\n            <Box>\n              <Typography variant="caption" sx={{ color: COLORS.textSecondary, mb: 0.75, display: \'block\', letterSpacing: \'0.05em\' }}>\n                USUARIO\n              </Typography>\n              <TextField\n                fullWidth\n                value={username}\n                onChange={(e) => setUsername(e.target.value)}\n                placeholder="Nombre de usuario"\n                autoComplete="username"\n                disabled={loading}\n                sx={{ \'& input\': { fontSize: \'0.9rem\' } }}\n              />\n            </Box>\n\n            <Box>\n              <Typography variant="caption" sx={{ color: COLORS.textSecondary, mb: 0.75, display: \'block\', letterSpacing: \'0.05em\' }}>\n                CONTRASEÑA\n              </Typography>\n              <TextField\n                fullWidth\n                type={showPwd ? \'text\' : \'password\'}\n                value={password}\n                onChange={(e) => setPassword(e.target.value)}\n                placeholder="••••••••"\n                autoComplete="current-password"\n                disabled={loading}\n                InputProps={{\n                  endAdornment: (\n                    <InputAdornment position="end">\n                      <IconButton onClick={() => setShowPwd(!showPwd)} edge="end" size="small" sx={{ color: COLORS.textMuted }}>\n                        {showPwd ? <VisibilityOff fontSize="small" /> : <Visibility fontSize="small" />}\n                      </IconButton>\n                    </InputAdornment>\n                  ),\n                }}\n                sx={{ \'& input\': { fontSize: \'0.9rem\' } }}\n              />\n            </Box>\n\n            <Button\n              type="submit"\n              variant="contained"\n              fullWidth\n              disabled={loading}\n              size="large"\n              sx={{ mt: 1, py: 1.5, fontSize: \'0.9rem\' }}\n            >\n              {loading ? <CircularProgress size={20} sx={{ color: COLORS.black }} /> : \'Ingresar\'}\n            </Button>\n          </Box>\n\n          <Typography variant="caption" sx={{ display: \'block\', mt: 4, color: COLORS.textMuted, textAlign: \'center\' }}>\n            Plataforma de uso interno. Acceso solo personal autorizado.\n          </Typography>\n        </Box>\n      </Box>\n    </Box>\n  )\n}\n'

FILES[r"frontend\\src\\pages\\PayrollPage.jsx"] = 'import { useEffect, useState, useCallback } from \'react\'\nimport {\n  Box, Typography, Button, Table, TableBody, TableCell,\n  TableContainer, TableHead, TableRow, Paper, Chip, CircularProgress,\n  Dialog, DialogTitle, DialogContent, DialogActions, TextField,\n  Grid, MenuItem, Alert, Tooltip, IconButton,\n} from \'@mui/material\'\nimport { AddOutlined, CheckCircleOutlined, ReceiptLongOutlined } from \'@mui/icons-material\'\nimport { payrollApi, employeesApi } from \'../services/api\'\nimport { useAuthStore } from \'../context/authStore\'\nimport { COLORS } from \'../theme/theme\'\n\nconst statusColor = {\n  borrador: \'warning\',\n  procesado: \'default\',\n  pagado: \'success\',\n  anulado: \'error\',\n}\n\nconst emptyForm = {\n  employee_id: \'\', period_start: \'\', period_end: \'\',\n  overtime_hours: \'0\', bonuses: \'0\', other_deductions: \'0\', notes: \'\',\n}\n\nexport default function PayrollPage() {\n  const { user } = useAuthStore()\n  const [payrolls, setPayrolls]   = useState([])\n  const [employees, setEmployees] = useState([])\n  const [loading, setLoading]     = useState(true)\n  const [openForm, setOpenForm]   = useState(false)\n  const [saving, setSaving]       = useState(false)\n  const [error, setError]         = useState(\'\')\n  const [form, setForm]           = useState(emptyForm)\n\n  const load = useCallback(async () => {\n    setLoading(true)\n    try {\n      const [pr, er] = await Promise.all([payrollApi.list(), employeesApi.list()])\n      setPayrolls(pr.data)\n      setEmployees(er.data)\n    } catch { /* ignore */ }\n    finally { setLoading(false) }\n  }, [])\n\n  useEffect(() => { load() }, [load])\n\n  const handleCreate = async () => {\n    setSaving(true); setError(\'\')\n    try {\n      await payrollApi.create({\n        ...form,\n        employee_id:      parseInt(form.employee_id),\n        overtime_hours:   parseFloat(form.overtime_hours),\n        bonuses:          parseFloat(form.bonuses),\n        other_deductions: parseFloat(form.other_deductions),\n      })\n      setOpenForm(false)\n      setForm(emptyForm)\n      load()\n    } catch (e) {\n      setError(e.response?.data?.detail || \'Error al crear nómina\')\n    } finally { setSaving(false) }\n  }\n\n  const handleApprove = async (id) => {\n    if (!confirm(\'¿Aprobar esta nómina?\')) return\n    try { await payrollApi.approve(id); load() } catch { /* ignore */ }\n  }\n\n  const fmt = (v) => `$${parseFloat(v).toLocaleString(\'es-PA\', { minimumFractionDigits: 2 })}`\n  const field = (key, value) => setForm(prev => ({ ...prev, [key]: value }))\n\n  return (\n    <Box>\n      <Box sx={{ display: \'flex\', justifyContent: \'space-between\', alignItems: \'flex-start\', mb: 4 }}>\n        <Box>\n          <Typography variant="h4" sx={{ color: COLORS.textPrimary, mb: 0.5 }}>Nóminas</Typography>\n          <Typography variant="body2" sx={{ color: COLORS.textSecondary }}>{payrolls.length} registros</Typography>\n        </Box>\n        <Button variant="contained" startIcon={<AddOutlined />} onClick={() => setOpenForm(true)} size="small">\n          Generar nómina\n        </Button>\n      </Box>\n\n      <TableContainer component={Paper} sx={{ borderRadius: 3 }}>\n        <Table size="small">\n          <TableHead>\n            <TableRow>\n              {[\'ID\', \'Empleado\', \'Período\', \'Salario Bruto\', \'Deducciones\', \'Salario Neto\', \'Estado\', \'Acciones\'].map(h => (\n                <TableCell key={h}>{h}</TableCell>\n              ))}\n            </TableRow>\n          </TableHead>\n          <TableBody>\n            {loading ? (\n              <TableRow>\n                <TableCell colSpan={8} sx={{ textAlign: \'center\', py: 4 }}>\n                  <CircularProgress size={24} sx={{ color: COLORS.accent }} />\n                </TableCell>\n              </TableRow>\n            ) : payrolls.length === 0 ? (\n              <TableRow>\n                <TableCell colSpan={8} sx={{ textAlign: \'center\', py: 6 }}>\n                  <ReceiptLongOutlined sx={{ fontSize: 40, color: COLORS.textMuted, mb: 1, display: \'block\', mx: \'auto\' }} />\n                  <Typography variant="body2" sx={{ color: COLORS.textMuted }}>Sin nóminas generadas</Typography>\n                </TableCell>\n              </TableRow>\n            ) : payrolls.map((p) => {\n              const emp = employees.find(e => e.id === p.employee_id)\n              return (\n                <TableRow key={p.id}>\n                  <TableCell sx={{ fontFamily: \'"DM Mono", monospace\', fontSize: \'0.75rem\', color: COLORS.textMuted }}>#{p.id}</TableCell>\n                  <TableCell sx={{ fontWeight: 500 }}>{emp ? `${emp.first_name} ${emp.last_name}` : `ID ${p.employee_id}`}</TableCell>\n                  <TableCell sx={{ fontFamily: \'"DM Mono", monospace\', fontSize: \'0.75rem\' }}>\n                    {p.period_start} → {p.period_end}\n                  </TableCell>\n                  <TableCell sx={{ fontFamily: \'"DM Mono", monospace\', fontSize: \'0.8rem\' }}>{fmt(p.gross_salary)}</TableCell>\n                  <TableCell sx={{ fontFamily: \'"DM Mono", monospace\', fontSize: \'0.8rem\', color: COLORS.error }}>{fmt(p.total_deductions)}</TableCell>\n                  <TableCell sx={{ fontFamily: \'"DM Mono", monospace\', fontSize: \'0.85rem\', fontWeight: 700, color: COLORS.success }}>{fmt(p.net_salary)}</TableCell>\n                  <TableCell>\n                    <Chip label={p.status} size="small" color={statusColor[p.status] || \'default\'} />\n                  </TableCell>\n                  <TableCell>\n                    {p.status === \'borrador\' && user?.role === \'admin\' && (\n                      <Tooltip title="Aprobar nómina">\n                        <IconButton size="small" onClick={() => handleApprove(p.id)}\n                          sx={{ color: COLORS.textMuted, \'&:hover\': { color: COLORS.success } }}>\n                          <CheckCircleOutlined sx={{ fontSize: 17 }} />\n                        </IconButton>\n                      </Tooltip>\n                    )}\n                  </TableCell>\n                </TableRow>\n              )\n            })}\n          </TableBody>\n        </Table>\n      </TableContainer>\n\n      {/* Create dialog */}\n      <Dialog open={openForm} onClose={() => setOpenForm(false)} maxWidth="sm" fullWidth PaperProps={{ sx: { borderRadius: 3 } }}>\n        <DialogTitle sx={{ fontFamily: \'"Syne", sans-serif\', pb: 1 }}>Generar Nómina</DialogTitle>\n        <DialogContent>\n          {error && <Alert severity="error" sx={{ mb: 2 }}>{error}</Alert>}\n          <Grid container spacing={2} sx={{ mt: 0.5 }}>\n            <Grid item xs={12}>\n              <TextField fullWidth select label="Empleado" value={form.employee_id} onChange={e => field(\'employee_id\', e.target.value)}>\n                {employees.map(e => (\n                  <MenuItem key={e.id} value={e.id}>{e.first_name} {e.last_name} — {e.employee_code}</MenuItem>\n                ))}\n              </TextField>\n            </Grid>\n            <Grid item xs={6}>\n              <TextField fullWidth label="Inicio período" type="date" value={form.period_start}\n                onChange={e => field(\'period_start\', e.target.value)} InputLabelProps={{ shrink: true }} />\n            </Grid>\n            <Grid item xs={6}>\n              <TextField fullWidth label="Fin período" type="date" value={form.period_end}\n                onChange={e => field(\'period_end\', e.target.value)} InputLabelProps={{ shrink: true }} />\n            </Grid>\n            <Grid item xs={4}>\n              <TextField fullWidth label="Horas extra" type="number" value={form.overtime_hours} onChange={e => field(\'overtime_hours\', e.target.value)} />\n            </Grid>\n            <Grid item xs={4}>\n              <TextField fullWidth label="Bonificaciones" type="number" value={form.bonuses} onChange={e => field(\'bonuses\', e.target.value)} />\n            </Grid>\n            <Grid item xs={4}>\n              <TextField fullWidth label="Otras deducciones" type="number" value={form.other_deductions} onChange={e => field(\'other_deductions\', e.target.value)} />\n            </Grid>\n            <Grid item xs={12}>\n              <TextField fullWidth label="Notas (opcional)" value={form.notes} onChange={e => field(\'notes\', e.target.value)} multiline rows={2} />\n            </Grid>\n          </Grid>\n        </DialogContent>\n        <DialogActions sx={{ px: 3, pb: 3 }}>\n          <Button onClick={() => setOpenForm(false)} disabled={saving}>Cancelar</Button>\n          <Button variant="contained" onClick={handleCreate} disabled={saving}>\n            {saving ? <CircularProgress size={18} sx={{ color: COLORS.black }} /> : \'Calcular y guardar\'}\n          </Button>\n        </DialogActions>\n      </Dialog>\n    </Box>\n  )\n}\n'

FILES[r"frontend\\src\\pages\\UsersPage.jsx"] = 'import { useEffect, useState, useCallback } from \'react\'\nimport {\n  Box, Typography, Table, TableBody, TableCell, TableContainer,\n  TableHead, TableRow, Paper, Chip, IconButton, Tooltip, CircularProgress,\n  Button, Dialog, DialogTitle, DialogContent, DialogActions,\n  TextField, Grid, MenuItem, Alert,\n} from \'@mui/material\'\nimport { BlockOutlined, CheckCircleOutlined, AddOutlined } from \'@mui/icons-material\'\nimport { usersApi, authApi } from \'../services/api\'\nimport { COLORS } from \'../theme/theme\'\n\nconst emptyForm = { email: \'\', username: \'\', full_name: \'\', role: \'operador_nomina\', password: \'\' }\n\nexport default function UsersPage() {\n  const [users, setUsers]       = useState([])\n  const [loading, setLoading]   = useState(true)\n  const [openForm, setOpenForm] = useState(false)\n  const [saving, setSaving]     = useState(false)\n  const [error, setError]       = useState(\'\')\n  const [form, setForm]         = useState(emptyForm)\n\n  const load = useCallback(async () => {\n    setLoading(true)\n    try { const res = await usersApi.list(); setUsers(res.data) } catch { /* ignore */ }\n    finally { setLoading(false) }\n  }, [])\n\n  useEffect(() => { load() }, [load])\n\n  const handleToggle = async (id) => {\n    try { await usersApi.toggleActive(id); load() } catch { /* ignore */ }\n  }\n\n  const handleCreate = async () => {\n    setSaving(true); setError(\'\')\n    try {\n      await authApi.register(form)\n      setOpenForm(false)\n      setForm(emptyForm)\n      load()\n    } catch (e) { setError(e.response?.data?.detail || \'Error al crear usuario\') }\n    finally { setSaving(false) }\n  }\n\n  const field = (key, value) => setForm(prev => ({ ...prev, [key]: value }))\n\n  return (\n    <Box>\n      <Box sx={{ display: \'flex\', justifyContent: \'space-between\', alignItems: \'flex-start\', mb: 4 }}>\n        <Box>\n          <Typography variant="h4" sx={{ color: COLORS.textPrimary, mb: 0.5 }}>Usuarios del Sistema</Typography>\n          <Typography variant="body2" sx={{ color: COLORS.textSecondary }}>{users.length} usuarios registrados</Typography>\n        </Box>\n        <Button variant="contained" startIcon={<AddOutlined />} onClick={() => setOpenForm(true)} size="small">\n          Nuevo usuario\n        </Button>\n      </Box>\n\n      <TableContainer component={Paper} sx={{ borderRadius: 3 }}>\n        <Table size="small">\n          <TableHead>\n            <TableRow>\n              {[\'Usuario\', \'Nombre completo\', \'Correo\', \'Rol\', \'Último acceso\', \'Estado\', \'Acciones\'].map(h => (\n                <TableCell key={h}>{h}</TableCell>\n              ))}\n            </TableRow>\n          </TableHead>\n          <TableBody>\n            {loading ? (\n              <TableRow>\n                <TableCell colSpan={7} sx={{ textAlign: \'center\', py: 4 }}>\n                  <CircularProgress size={24} sx={{ color: COLORS.accent }} />\n                </TableCell>\n              </TableRow>\n            ) : users.map((u) => (\n              <TableRow key={u.id}>\n                <TableCell sx={{ fontFamily: \'"DM Mono", monospace\', fontSize: \'0.8rem\', color: COLORS.accent }}>{u.username}</TableCell>\n                <TableCell sx={{ fontWeight: 500 }}>{u.full_name}</TableCell>\n                <TableCell sx={{ fontSize: \'0.85rem\', color: COLORS.textSecondary }}>{u.email}</TableCell>\n                <TableCell>\n                  <Chip\n                    label={u.role === \'admin\' ? \'Admin\' : \'Operador\'}\n                    size="small"\n                    color={u.role === \'admin\' ? \'primary\' : \'default\'}\n                    sx={{ fontSize: \'0.7rem\', height: 22 }}\n                  />\n                </TableCell>\n                <TableCell sx={{ fontSize: \'0.78rem\', fontFamily: \'"DM Mono", monospace\', color: COLORS.textMuted }}>\n                  {u.last_login ? new Date(u.last_login).toLocaleString(\'es-PA\') : \'Nunca\'}\n                </TableCell>\n                <TableCell>\n                  <Chip label={u.is_active ? \'Activo\' : \'Inactivo\'} size="small" color={u.is_active ? \'success\' : \'error\'} />\n                </TableCell>\n                <TableCell>\n                  <Tooltip title={u.is_active ? \'Desactivar\' : \'Activar\'}>\n                    <IconButton size="small" onClick={() => handleToggle(u.id)}\n                      sx={{ color: COLORS.textMuted, \'&:hover\': { color: u.is_active ? COLORS.error : COLORS.success } }}>\n                      {u.is_active ? <BlockOutlined sx={{ fontSize: 16 }} /> : <CheckCircleOutlined sx={{ fontSize: 16 }} />}\n                    </IconButton>\n                  </Tooltip>\n                </TableCell>\n              </TableRow>\n            ))}\n          </TableBody>\n        </Table>\n      </TableContainer>\n\n      <Dialog open={openForm} onClose={() => setOpenForm(false)} maxWidth="xs" fullWidth PaperProps={{ sx: { borderRadius: 3 } }}>\n        <DialogTitle sx={{ fontFamily: \'"Syne", sans-serif\', pb: 1 }}>Nuevo Usuario</DialogTitle>\n        <DialogContent>\n          {error && <Alert severity="error" sx={{ mb: 2 }}>{error}</Alert>}\n          <Grid container spacing={2} sx={{ mt: 0.5 }}>\n            <Grid item xs={12}><TextField fullWidth label="Nombre completo" value={form.full_name}  onChange={e => field(\'full_name\', e.target.value)} /></Grid>\n            <Grid item xs={12}><TextField fullWidth label="Usuario"         value={form.username}   onChange={e => field(\'username\', e.target.value)} /></Grid>\n            <Grid item xs={12}><TextField fullWidth label="Correo"          value={form.email}      onChange={e => field(\'email\', e.target.value)} type="email" /></Grid>\n            <Grid item xs={12}><TextField fullWidth label="Contraseña"      value={form.password}   onChange={e => field(\'password\', e.target.value)} type="password" /></Grid>\n            <Grid item xs={12}>\n              <TextField fullWidth select label="Rol" value={form.role} onChange={e => field(\'role\', e.target.value)}>\n                <MenuItem value="operador_nomina">Operador de Nómina</MenuItem>\n                <MenuItem value="admin">Administrador</MenuItem>\n              </TextField>\n            </Grid>\n          </Grid>\n        </DialogContent>\n        <DialogActions sx={{ px: 3, pb: 3 }}>\n          <Button onClick={() => setOpenForm(false)} disabled={saving}>Cancelar</Button>\n          <Button variant="contained" onClick={handleCreate} disabled={saving}>\n            {saving ? <CircularProgress size={18} sx={{ color: COLORS.black }} /> : \'Crear usuario\'}\n          </Button>\n        </DialogActions>\n      </Dialog>\n    </Box>\n  )\n}\n'

FILES[r"frontend\\src\\services\\api.js"] = "import axios from 'axios'\nimport { useAuthStore } from '../context/authStore'\n\nconst api = axios.create({\n  baseURL: '/api/v1',\n  timeout: 15000,\n  headers: { 'Content-Type': 'application/json' },\n})\n\n// Attach token to every request\napi.interceptors.request.use(\n  (config) => {\n    const token = useAuthStore.getState().accessToken\n    if (token) config.headers.Authorization = `Bearer ${token}`\n    return config\n  },\n  (error) => Promise.reject(error)\n)\n\n// Auto-refresh token on 401\napi.interceptors.response.use(\n  (response) => response,\n  async (error) => {\n    const original = error.config\n    const store = useAuthStore.getState()\n\n    if (error.response?.status === 401 && !original._retry && store.refreshToken) {\n      original._retry = true\n      try {\n        const res = await axios.post('/api/v1/auth/refresh', {\n          refresh_token: store.refreshToken,\n        })\n        const { access_token, refresh_token, user } = res.data\n        store.setTokens(access_token, refresh_token)\n        store.setUser(user)\n        original.headers.Authorization = `Bearer ${access_token}`\n        return api(original)\n      } catch {\n        store.logout()\n        window.location.href = '/login'\n      }\n    }\n\n    return Promise.reject(error)\n  }\n)\n\nexport default api\n\nexport const authApi = {\n  login: (username, password) => api.post('/auth/login', { username, password }),\n  me: () => api.get('/auth/me'),\n  register: (data) => api.post('/auth/register', data),\n}\n\nexport const employeesApi = {\n  list: (params) => api.get('/employees', { params }),\n  get: (id) => api.get(`/employees/${id}`),\n  create: (data) => api.post('/employees', data),\n  update: (id, data) => api.patch(`/employees/${id}`, data),\n  deactivate: (id) => api.delete(`/employees/${id}`),\n}\n\nexport const payrollApi = {\n  list: (params) => api.get('/payroll', { params }),\n  create: (data) => api.post('/payroll', data),\n  approve: (id) => api.patch(`/payroll/${id}/approve`),\n}\n\nexport const usersApi = {\n  list: () => api.get('/users'),\n  toggleActive: (id) => api.patch(`/users/${id}/toggle-active`),\n}\n"

FILES[r"frontend\\src\\theme\\theme.js"] = 'import { createTheme, alpha } from \'@mui/material/styles\'\n\nexport const COLORS = {\n  black: \'#0A0A0A\',\n  darkSurface: \'#111111\',\n  cardBg: \'#171717\',\n  borderSubtle: \'#252525\',\n  textPrimary: \'#F0F0EC\',\n  textSecondary: \'#888880\',\n  textMuted: \'#555550\',\n  accent: \'#CBEF3B\',\n  accentHover: \'#B8DC28\',\n  accentMuted: alpha(\'#CBEF3B\', 0.12),\n  white: \'#FAFAF5\',\n  error: \'#FF5555\',\n  success: \'#4ADE80\',\n  warning: \'#FACC15\',\n}\n\nexport const theme = createTheme({\n  palette: {\n    mode: \'dark\',\n    primary: {\n      main: COLORS.accent,\n      light: COLORS.accent,\n      dark: COLORS.accentHover,\n      contrastText: COLORS.black,\n    },\n    secondary: {\n      main: COLORS.textSecondary,\n      contrastText: COLORS.textPrimary,\n    },\n    background: {\n      default: COLORS.black,\n      paper: COLORS.cardBg,\n    },\n    text: {\n      primary: COLORS.textPrimary,\n      secondary: COLORS.textSecondary,\n    },\n    error: { main: COLORS.error },\n    success: { main: COLORS.success },\n    warning: { main: COLORS.warning },\n    divider: COLORS.borderSubtle,\n  },\n  typography: {\n    fontFamily: \'"DM Sans", "Helvetica Neue", Arial, sans-serif\',\n    h1: { fontFamily: \'"Syne", "DM Sans", sans-serif\', fontWeight: 700, letterSpacing: \'-0.03em\' },\n    h2: { fontFamily: \'"Syne", "DM Sans", sans-serif\', fontWeight: 700, letterSpacing: \'-0.02em\' },\n    h3: { fontFamily: \'"Syne", "DM Sans", sans-serif\', fontWeight: 600, letterSpacing: \'-0.02em\' },\n    h4: { fontFamily: \'"Syne", "DM Sans", sans-serif\', fontWeight: 600, letterSpacing: \'-0.015em\' },\n    h5: { fontFamily: \'"Syne", "DM Sans", sans-serif\', fontWeight: 600 },\n    h6: { fontFamily: \'"Syne", "DM Sans", sans-serif\', fontWeight: 600 },\n    body1: { fontFamily: \'"DM Sans", sans-serif\', fontSize: \'0.9375rem\', lineHeight: 1.6 },\n    body2: { fontFamily: \'"DM Sans", sans-serif\', fontSize: \'0.8125rem\', lineHeight: 1.5 },\n    caption: { fontFamily: \'"DM Mono", monospace\', fontSize: \'0.75rem\', letterSpacing: \'0.04em\' },\n    overline: { fontFamily: \'"DM Mono", monospace\', fontSize: \'0.6875rem\', letterSpacing: \'0.1em\' },\n    button: { fontFamily: \'"DM Sans", sans-serif\', fontWeight: 600, letterSpacing: \'0.01em\' },\n  },\n  shape: { borderRadius: 12 },\n  components: {\n    MuiCssBaseline: {\n      styleOverrides: `\n        @import url(\'https://fonts.googleapis.com/css2?family=Syne:wght@400;600;700;800&family=DM+Sans:ital,opsz,wght@0,9..40,300;0,9..40,400;0,9..40,500;0,9..40,600;1,9..40,400&family=DM+Mono:wght@400;500&display=swap\');\n        * { box-sizing: border-box; }\n        body { background-color: ${COLORS.black}; color: ${COLORS.textPrimary}; }\n        ::-webkit-scrollbar { width: 6px; height: 6px; }\n        ::-webkit-scrollbar-track { background: ${COLORS.darkSurface}; }\n        ::-webkit-scrollbar-thumb { background: ${COLORS.borderSubtle}; border-radius: 3px; }\n        ::-webkit-scrollbar-thumb:hover { background: ${COLORS.textMuted}; }\n      `,\n    },\n    MuiButton: {\n      styleOverrides: {\n        root: { borderRadius: 8, textTransform: \'none\', fontWeight: 600, letterSpacing: \'0.01em\', transition: \'all 0.2s ease\' },\n        contained: {\n          backgroundColor: COLORS.accent,\n          color: COLORS.black,\n          \'&:hover\': { backgroundColor: COLORS.accentHover, transform: \'translateY(-1px)\', boxShadow: `0 4px 20px ${alpha(COLORS.accent, 0.35)}` },\n        },\n        outlined: {\n          borderColor: COLORS.borderSubtle,\n          color: COLORS.textPrimary,\n          \'&:hover\': { borderColor: COLORS.accent, backgroundColor: COLORS.accentMuted },\n        },\n        text: {\n          color: COLORS.textSecondary,\n          \'&:hover\': { color: COLORS.textPrimary, backgroundColor: alpha(COLORS.white, 0.04) },\n        },\n      },\n    },\n    MuiCard: {\n      styleOverrides: {\n        root: { backgroundColor: COLORS.cardBg, border: `1px solid ${COLORS.borderSubtle}`, borderRadius: 16, backgroundImage: \'none\' },\n      },\n    },\n    MuiPaper: {\n      styleOverrides: {\n        root: { backgroundImage: \'none\', backgroundColor: COLORS.cardBg, border: `1px solid ${COLORS.borderSubtle}` },\n      },\n    },\n    MuiTextField: {\n      defaultProps: { variant: \'outlined\', size: \'small\' },\n      styleOverrides: {\n        root: {\n          \'& .MuiOutlinedInput-root\': {\n            backgroundColor: COLORS.darkSurface,\n            borderRadius: 8,\n            \'& fieldset\': { borderColor: COLORS.borderSubtle },\n            \'&:hover fieldset\': { borderColor: COLORS.textMuted },\n            \'&.Mui-focused fieldset\': { borderColor: COLORS.accent },\n          },\n          \'& .MuiInputLabel-root.Mui-focused\': { color: COLORS.accent },\n        },\n      },\n    },\n    MuiChip: {\n      styleOverrides: {\n        root: { borderRadius: 6, fontFamily: \'"DM Mono", monospace\', fontSize: \'0.7rem\', fontWeight: 500 },\n        colorSuccess: { backgroundColor: alpha(COLORS.success, 0.15), color: COLORS.success },\n        colorError: { backgroundColor: alpha(COLORS.error, 0.15), color: COLORS.error },\n        colorWarning: { backgroundColor: alpha(COLORS.warning, 0.15), color: COLORS.warning },\n      },\n    },\n    MuiDrawer: {\n      styleOverrides: {\n        paper: { backgroundColor: COLORS.darkSurface, borderRight: `1px solid ${COLORS.borderSubtle}`, backgroundImage: \'none\' },\n      },\n    },\n    MuiAppBar: {\n      styleOverrides: {\n        root: { backgroundColor: alpha(COLORS.darkSurface, 0.85), backdropFilter: \'blur(20px)\', borderBottom: `1px solid ${COLORS.borderSubtle}`, boxShadow: \'none\' },\n      },\n    },\n    MuiTableHead: {\n      styleOverrides: {\n        root: {\n          \'& .MuiTableCell-root\': {\n            backgroundColor: COLORS.darkSurface,\n            color: COLORS.textSecondary,\n            fontFamily: \'"DM Mono", monospace\',\n            fontSize: \'0.7rem\',\n            letterSpacing: \'0.08em\',\n            textTransform: \'uppercase\',\n            borderBottom: `1px solid ${COLORS.borderSubtle}`,\n          },\n        },\n      },\n    },\n    MuiTableBody: {\n      styleOverrides: {\n        root: {\n          \'& .MuiTableRow-root\': { transition: \'background-color 0.15s ease\', \'&:hover\': { backgroundColor: alpha(COLORS.white, 0.02) } },\n          \'& .MuiTableCell-root\': { borderBottom: `1px solid ${COLORS.borderSubtle}`, color: COLORS.textPrimary },\n        },\n      },\n    },\n    MuiTooltip: {\n      styleOverrides: {\n        tooltip: { backgroundColor: COLORS.cardBg, border: `1px solid ${COLORS.borderSubtle}`, color: COLORS.textPrimary, fontSize: \'0.8rem\', borderRadius: 8 },\n      },\n    },\n    MuiAlert: {\n      styleOverrides: {\n        root: { borderRadius: 10, border: \'1px solid\' },\n        standardError: { backgroundColor: alpha(COLORS.error, 0.08), borderColor: alpha(COLORS.error, 0.25) },\n        standardSuccess: { backgroundColor: alpha(COLORS.success, 0.08), borderColor: alpha(COLORS.success, 0.25) },\n      },\n    },\n    MuiLinearProgress: {\n      styleOverrides: {\n        root: { borderRadius: 4, backgroundColor: COLORS.borderSubtle },\n        bar: { borderRadius: 4, backgroundColor: COLORS.accent },\n      },\n    },\n    MuiListItemButton: {\n      styleOverrides: {\n        root: {\n          borderRadius: 10,\n          margin: \'2px 8px\',\n          transition: \'all 0.15s ease\',\n          \'&:hover\': { backgroundColor: alpha(COLORS.white, 0.04) },\n          \'&.Mui-selected\': {\n            backgroundColor: COLORS.accentMuted,\n            color: COLORS.accent,\n            \'&:hover\': { backgroundColor: alpha(COLORS.accent, 0.18) },\n            \'& .MuiListItemIcon-root\': { color: COLORS.accent },\n          },\n        },\n      },\n    },\n    MuiDivider: {\n      styleOverrides: { root: { borderColor: COLORS.borderSubtle } },\n    },\n  },\n})\n'

FILES[r"frontend\\vite.config.js"] = "import { defineConfig } from 'vite'\nimport react from '@vitejs/plugin-react'\n\nexport default defineConfig({\n  plugins: [react()],\n  server: {\n    port: 5173,\n    proxy: {\n      '/api': {\n        target: 'http://localhost:8000',\n        changeOrigin: true,\n      },\n    },\n  },\n})\n"


def install():
    created = 0
    print(f"\n  PayApp Installer")
    print(f"  Destino: {BASE}\n")
    for rel, content in FILES.items():
        full_path = os.path.join(BASE, rel)
        dir_path = os.path.dirname(full_path)
        os.makedirs(dir_path, exist_ok=True)
        with open(full_path, "w", encoding="utf-8") as f:
            f.write(content)
        print(f"  ✓ {rel}")
        created += 1
    print(f"\n  {created} archivos creados correctamente.")
    print(f"""
  ─────────────────────────────────────────────
  SIGUIENTES PASOS:

  1. BACKEND
     cd {BASE}\\backend
     python -m venv venv
     venv\\Scripts\\activate
     pip install -r requirements.txt
     python seed.py
     uvicorn app.main:app --reload --port 8000

  2. FRONTEND (otra terminal)
     cd {BASE}\\frontend
     npm install
     npm run dev

  Login inicial: admin / Admin123!
  App: http://localhost:5173
  API: http://localhost:8000/api/docs
  ─────────────────────────────────────────────
""")

if __name__ == "__main__":
    try:
        install()
    except Exception as e:
        print(f"Error: {e}")
        sys.exit(1)